        AND line_name = #{lineName}


        AND cancel_flag = #{cancelFlag}


        AND direction = #{direction}


        AND trip_type = #{tripType}


order by plan_depart_time

SELECT line_name as lineName, COUNT(*) as totalSchedules, SUM(CASE WHEN cancel_flag = 0 THEN 1 ELSE 0 END) as validSchedules, SUM(CASE WHEN cancel_flag = 1 THEN 1 ELSE 0 END) as canceledSchedules, CAST(SUM(CASE WHEN cancel_flag = 1 THEN 1 ELSE 0 END) AS DECIMAL(10,2)) / COUNT(*) * 100 as cancelRate FROM dim_schedules WHERE DATE(plan_depart_time) = #{date}
AND line_name = #{lineName}
GROUP BY line_name ORDER BY totalSchedules DESC

SELECT t.hour,
       COALESCE(f.flow, 0) as hourlyFlow,
       COALESCE(s.scheduleCount, 0) as scheduleCount,
       COALESCE(f.flow, 0) / NULLIF(COALESCE(s.scheduleCount, 0), 0) as matchRatio
FROM (
    SELECT HOUR(plan_depart_time) as hour
    FROM dim_schedules
    WHERE DATE(plan_depart_time) = #{date}
    AND line_name = #{lineName}
    AND cancel_flag = 0
    UNION
    SELECT stat_hour as hour
    FROM fact_station_flow
    WHERE DATE(stat_time) = #{date}
    AND line_name = #{lineName}
) t
LEFT JOIN (
    SELECT HOUR(plan_depart_time) as hour,
           COUNT(*) as scheduleCount
    FROM dim_schedules
    WHERE DATE(plan_depart_time) = #{date}
    AND line_name = #{lineName}
    AND cancel_flag = 0
    GROUP BY HOUR(plan_depart_time)
) s ON t.hour = s.hour
LEFT JOIN (
    SELECT stat_hour as hour,
           SUM(boarding_count + alighting_count) as flow
    FROM fact_station_flow
    WHERE DATE(stat_time) = #{date}
    AND line_name = #{lineName}
    GROUP BY stat_hour
) f ON t.hour = f.hour
ORDER BY t.hour
